import React, { useState, useRef, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { GoogleGenAI } from "@google/genai";

const BackgroundRemover: React.FC = () => {
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [resultUrl, setResultUrl] = useState<string | null>(null);
  const [resultBlob, setResultBlob] = useState<Blob | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isDone, setIsDone] = useState(false);
  const [isSaved, setIsSaved] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [error, setError] = useState<React.ReactNode | null>(null);
  const [needsKeySelection, setNeedsKeySelection] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Check auth and key status on mount
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setIsLoggedIn(!!session);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setIsLoggedIn(!!session);
    });

    checkKeyStatus();

    return () => subscription.unsubscribe();
  }, []);

  // Check if user has selected a key in AI Studio for image tasks
  const checkKeyStatus = async () => {
    if (window.aistudio) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      setNeedsKeySelection(!hasKey);
    }
  };

  // Convert File/Blob to base64 for Gemini API
  const fileToBase64 = (file: File | Blob): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        const base64String = (reader.result as string).split(',')[1];
        resolve(base64String);
      };
      reader.onerror = (error) => reject(error);
    });
  };

  // Handle file selection
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setSelectedFile(file);
      setPreviewUrl(URL.createObjectURL(file));
      setResultUrl(null);
      setResultBlob(null);
      setIsDone(false);
      setIsSaved(false);
      setError(null);
      checkKeyStatus();
    }
  };

  // Open the AI Studio key selection dialog
  const handleOpenKeySelection = async () => {
    if (window.aistudio) {
      try {
        await window.aistudio.openSelectKey();
        setNeedsKeySelection(false);
        setError(null);
        if (selectedFile) handleRemoveBackground();
      } catch (e) {
        console.error("Key selection failed", e);
      }
    }
  };

  // Process background removal using Gemini 2.5 Flash Image
  const handleRemoveBackground = async () => {
    if (!selectedFile) return;

    if (window.aistudio) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        setNeedsKeySelection(true);
        setError(
          <div className="text-center py-2 space-y-3">
            <p className="font-bold text-amber-600 uppercase">Action Required</p>
            <p className="text-[11px] text-slate-500 leading-relaxed">
              AI Background Removal requires a Google Cloud project key with active billing enabled.
            </p>
          </div>
        );
        return;
      }
    }

    setIsProcessing(true);
    setError(null);

    try {
      // Re-initialize for every call to use the most up-to-date API key
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const base64Data = await fileToBase64(selectedFile);

      const prompt = "Remove the background from this image. Identify the main subject and return only the subject on a transparent background as an image.";

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            { inlineData: { data: base64Data, mimeType: selectedFile.type } },
            { text: prompt }
          ]
        }
      });

      let foundImage = false;
      const candidate = response.candidates?.[0];
      if (candidate?.content?.parts) {
        for (const part of candidate.content.parts) {
          if (part.inlineData) {
            const base64Res = part.inlineData.data;
            const resMimeType = part.inlineData.mimeType || 'image/png';
            const dataUrl = `data:${resMimeType};base64,${base64Res}`;
            const res = await fetch(dataUrl);
            const blob = await res.blob();

            setResultBlob(blob);
            setResultUrl(dataUrl);
            setIsDone(true);
            foundImage = true;
            break;
          }
        }
      }

      if (!foundImage) throw new Error("The AI engine failed to return an image part with background removed.");
    } catch (err: any) {
      console.error('Extraction failure:', err);
      const msg = err.message || "";
      const isAuthError = msg.toLowerCase().includes("permission denied") || 
                          msg.toLowerCase().includes("api key") || 
                          msg.toLowerCase().includes("requested entity was not found") ||
                          msg.toLowerCase().includes("403") ||
                          msg.toLowerCase().includes("not found");

      if (isAuthError) {
        setNeedsKeySelection(true);
        setError(
          <div className="text-center py-2 space-y-3">
            <p className="font-black text-red-600 uppercase">Access Denied</p>
            <p className="text-[11px] text-slate-500 leading-relaxed">
              Authentication failed. Please select a Google Cloud project with an active billing account in the AI Studio dialog.
            </p>
            <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" rel="noopener noreferrer" className="text-[10px] text-primary-500 hover:underline">Billing Documentation</a>
          </div>
        );
      } else {
        setError(`Processing failed: ${msg || "An unexpected error occurred."}`);
      }
