import React, { useState, useRef, useEffect } from 'react';
import { supabase } from '../lib/supabase';

const BackgroundRemover: React.FC = () => {
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [resultUrl, setResultUrl] = useState<string | null>(null);
  const [resultBlob, setResultBlob] = useState<Blob | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isDone, setIsDone] = useState(false);
  const [isSaved, setIsSaved] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setIsLoggedIn(!!session);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setIsLoggedIn(!!session);
    });

    return () => subscription.unsubscribe();
  }, []);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setSelectedFile(file);
      setPreviewUrl(URL.createObjectURL(file));
      setResultUrl(null);
      setResultBlob(null);
      setIsDone(false);
      setIsSaved(false);
      setError(null);
    }
  };

  const handleRemoveBackground = async () => {
    if (!selectedFile) return;

    setIsProcessing(true);
    setError(null);

    try {
      const formData = new FormData();
      formData.append("image", selectedFile);

      // Fix: Access environment variables using process.env exclusively to avoid TypeScript errors with import.meta.env
      const apiKey = (process.env as any).VITE_PIXIAN_API_KEY;

      if (!apiKey) {
        throw new Error("Pixian API Key missing. Please ensure VITE_PIXIAN_API_KEY is configured in your environment.");
      }

      // Pixian API v2 endpoint
      const res = await fetch("https://api.pixian.ai/api/v2/remove-background", {
        method: "POST",
        headers: {
          "X-Api-Key": apiKey,
        },
        body: formData,
      });

      if (!res.ok) {
        const errData = await res.json().catch(() => ({}));
        if (res.status === 401 || res.status === 403) {
          throw new Error("Invalid Pixian API Key. Please verify your configuration.");
        }
        throw new Error(errData.message || `Pixian API Error: ${res.status}. Check your Pixian account balance.`);
      }

      const blob = await res.blob();
      const url = URL.createObjectURL(blob);

      setResultBlob(blob);
      setResultUrl(url);
      setIsDone(true);
    } catch (err: any) {
      console.error('Background removal failure:', err);
      setError(err.message || "An unexpected error occurred during processing.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleSaveToLibrary = async () => {
    if (!resultBlob || !selectedFile) return;
    setIsSaving(true);
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session?.user) throw new Error("Please log in to save assets.");

      const fileName = `${Date.now()}_nobg_${selectedFile.name.split('.')[0]}.png`;
      const filePath = `${session.user.id}/${fileName}`;

      const { error: uploadError } = await supabase.storage.from('images').upload(filePath, resultBlob);
      if (uploadError) throw uploadError;

      const { data: { publicUrl } } = supabase.storage.from('images').getPublicUrl(filePath);

      const { error: dbError } = await supabase.from('images').insert([{
        user_id: session.user.id,
        name: selectedFile.name,
        url: publicUrl,
        type: 'bg-removed',
        date: new Date().toISOString(),
        size: `${(resultBlob.size / 1024).toFixed(1)} KB`
      }]);

      if (dbError) throw dbError;

      setIsSaved(true);
    } catch (err: any) {
      alert(err.message);
    } finally {
